// اقرأ جميع الصفوف القادمة من Google Sheets
const rows = $input.all();

let maxId = 0;

for (const row of rows) {
  // غير "ID" لو اسم العمود عندك مختلف
  const id = row.json.ID;

  if (!id) continue;

  // يستخرج الرقم من ID مثل MN-000123 => 123
  const match = String(id).match(/\d+/);

  if (!match) continue;

  const number = parseInt(match[0], 10);

  if (number > maxId) {
    maxId = number;
  }
}

const newId = "MN-" + String(maxId + 1).padStart(1, "0");

// خذ بيانات العقار من النود السابقة (عدل الاسم لو مختلف)
const property = $('Validate Data').first().json;

return [
  {
    json: {
      ...property,
      ID: newId
    }
  }
];

