  const fields = $('check_required_fields').item.json.output;
  let missing = [];

  if (!fields['رقم العميل']) missing.push("• رقم العميل");
  if (!fields['المساحه'] && !fields['المساحة']) missing.push("• المساحة التقريبية");
  if (!fields['الميزانيه'] && !fields['الميزانية']) missing.push("• الميزانية المتاحة");

  return `⚠️ عذراً، هناك بيانات ناقصة لإتمام الطلب. يرجى تزويدنا بـ:\n\n${missing.join('\n')}\n\nيرجى إعادة إرسال الرسالة كاملة بعد التعديل.`;
})()
}}

