const source = $json.output ?? $json;
const first = (...values) => values.find((value) => value !== undefined && value !== null && String(value).trim() !== '') ?? '';

return [{
  json: {
    property_id: $json.ID ?? '',
    property_type: first(source['نوع العقار '], source['نوع العقار']),
    property_location: first(source['المنطقة'], source['العنوان '], source['العنوان']),
    property_area: first(source['المساحة'], source['مساحة الأرض'], source['المساحة المبنية']),
    property_price: first(source['السعر الاجمالي'], source['سعر البيع'], source['الايجار']),
  },
}];

const property = $('Prepare Request Follow-up').item.json;
const normalize = (value) => String(value ?? '')
  .toLowerCase()
  .replace(/[أإآ]/g, 'ا')
  .replace(/ة/g, 'ه')
  .replace(/ى/g, 'ي')
  .replace(/[^ء-يa-z0-9]/g, '');

const propertyType = normalize(property.property_type);
const propertyLocation = normalize(property.property_location);

return $input.all()
  .filter(({ json: request }) => {
    const chatId = request['Telegram Chat ID'];
    const requestType = normalize(request['نوع العقار']);
    const locations = ['الموقع 1', 'الموقع 2', 'الموقع 3']
      .map((key) => normalize(request[key]))
      .filter(Boolean);
    const typeMatch = propertyType && requestType && (propertyType.includes(requestType) || requestType.includes(propertyType));
    const locationMatch = locations.length > 0 && propertyLocation && locations.some((location) => propertyLocation.includes(location) || location.includes(propertyLocation));
    return Boolean(chatId && typeMatch && locationMatch);
  })
  .map(({ json: request }) => ({
    json: {
      chat_id: request['Telegram Chat ID'],
      client_name: request['اسم العميل '] || 'العميل',
      property_id: property.property_id,
      property_type: property.property_type,
      property_location: property.property_location,
      property_area: property.property_area,
      property_price: property.property_price,
    },
  }));

